import React from 'react';
import { View, ActivityIndicator } from 'react-native';
import { Text } from '@semparar/design-system-app';
import type { MyOrdersDetailProps } from './Models';

const MyOrdersDetailView = (props: MyOrdersDetailProps) => {
  const { isLoading, hasError, cardTitle } = props;

  if (isLoading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  if (hasError) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <Text>Erro ao carregar detalhes</Text>
      </View>
    );
  }

  return (
    <View style={{ flex: 1 }}>
      <Text>{cardTitle}</Text>
    </View>
  );
};

export default MyOrdersDetailView;

