import {
  Box,
  CardPoints,
  Icon,
  ListCardTransition,
  LoadingFooter,
  SearchUsed,
  SeparatorHorizontal,
  Tabs,
  Text,
} from '@semparar/design-system-app';
import theme from '@semparar/design-system-app/src/styles/theme';
import React, { FC } from 'react';
import { RefreshControl } from 'react-native';
import ApiError from '../../atomic/organisms/ApiError';
import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
import PointsInfoBottomSheet from '../../atomic/organisms/PointsInfoBottomSheet';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { getPlaceholder, useExtractRewardProgramScreen } from './index';
import type {
  EmptyListProps,
  ExtractRewardProgramProps,
  TransactionsListProps,
} from './Models';

const EmptyList = React.memo<EmptyListProps>(({ label }) => (
  <Box width="100%" justify="center" align="center">
    <Icon
      name="icon-invoice-error"
      size="lg"
      color="INTENSE_COLOR_02"
      mt="meddium"
    />
    <Text
      type="paragraphLG"
      pd="innerGreat"
      color="INTENSE_COLOR_03"
      align="center"
    >
      {label}
    </Text>
  </Box>
));

EmptyList.displayName = 'EmptyList';

const TransactionsList = React.memo<TransactionsListProps>(({
  items,
  isLoading,
}) => (
  <ListCardTransition
    items={items}
    isLoading={isLoading}
    scrollEnabled={false}
    mb="meddium"
  />
));

TransactionsList.displayName = 'TransactionsList';

const LoadingMore = React.memo(() => (
  <Box width="100%" align="center" justify="center" mt="small" mb="small">
    <LoadingFooter />
  </Box>
));

LoadingMore.displayName = 'LoadingMore';

const ExtractRewardProgram: FC<ExtractRewardProgramProps> = ({
  route,
  navigation,
}) => {
  const {
    hasError,
    handleGoBack,
    pointsAvailable,
    isLoadingExtract,
    isLoadingMore,
    isLoadingBalance,
    isRefreshing,
    transactionsData,
    searchText,
    activeFiltersCount,
    transactionsEmptyMessage,
    shouldShowTransactionsList,
    filterGroups,
    initialFilters,
    modalizeRefInfo,
    modalizeRefFilters,
    handleSearchChange,
    handleRefresh,
    handleError,
    handleScroll,
    handleIconInfoPress,
    handleFilterIconPress,
    handleApplyFilters,
    handleTabChange,
    handleSearchPressIn,
  } = useExtractRewardProgramScreen({
    route,
    navigation,
  });

  if (hasError) {
    return (
      <ApiError
        title="Algo deu errado!"
        subTitle="Por favor, tente de novo."
        isLoading={isLoadingExtract}
        onPress={handleError}
      />
    );
  }

  return (
    <>
      <BasicScreen
        errorButtonOnPress={handleError}
        leftIconOnPress={handleGoBack}
        title="Extrato"
        hasScroll
        scrollViewProps={{
          refreshControl: (
            <RefreshControl
              onRefresh={handleRefresh}
              refreshing={isRefreshing}
              tintColor={theme.colors.BRAND_BASE_01}
            />
          ),
          onScroll: handleScroll,
          scrollEventThrottle: 16,
        }}
      >
        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
          <CardPoints
            icon="icon-benefits"
            iconInfo="icon-help"
            title="Pontos disponíveis"
            valuePoints={
              pointsAvailable
                ? Math.floor(pointsAvailable).toLocaleString('pt-br')
                : '0'
            }
            hideBottom
            isLoading={isLoadingBalance}
            onPressIconInfo={handleIconInfoPress}
          />

          <Text
            type="paragraphXXXL"
            mb="xxxxs"
            mt="xxs"
            color="INTENSE_COLOR_05"
          >
            Lançamentos
          </Text>

          <SeparatorHorizontal
            borderWidth="smaller"
            borderColor="BRAND_COMPLEMENT_02"
            height={1}
            mb="xxxxs"
            width="100%"
          />
          <SearchUsed
            placeholder={getPlaceholder()}
            onChangeText={handleSearchChange}
            value={searchText}
            showIcon={!!activeFiltersCount}
            firstIcon={undefined}
            onPressIn={handleSearchPressIn}
            numberIcon={activeFiltersCount}
            secondIcon="icon-filter-settings"
            secondOnPress={handleFilterIconPress}
            showFilter
          />
        </Box>

        <Box
          ml={isLoadingExtract ? 'xs' : 'none'}
          mr={isLoadingExtract ? 'xs' : 'none'}
        >
          <Tabs
            items={[
              {
                id: 0,
                title: 'Todos',
                component: (
                  <TransactionsList
                    items={transactionsData}
                    isLoading={isLoadingExtract}
                  />
                ),
              },
              {
                id: 1,
                title: 'A expirar',
                component: <></>,
              },
            ]}
            showBackground={false}
            hasScroll={false}
            loadingType="light"
            onChange={handleTabChange}
            type="options"
            isLoading={isLoadingExtract}
          />
          {!shouldShowTransactionsList && (
            <EmptyList label={transactionsEmptyMessage} />
          )}
          {isLoadingMore && <LoadingMore />}
        </Box>
      </BasicScreen>
      <PointsInfoBottomSheet modalizeRef={modalizeRefInfo} />
      {filterGroups.length > 0 && (
        <FiltersBottomSheet
          modalizeRef={modalizeRefFilters}
          filterGroups={filterGroups}
          onApplyFilters={handleApplyFilters}
          initialFilters={initialFilters}
        />
      )}
    </>
  );
};

export default ExtractRewardProgram;

import {
  BackDropBottom,
  Box,
  Button,
  CardActivity,
  DetailTransactionValue,
  SeparatorHorizontal,
  TagLabel,
  Text,
} from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Linking } from 'react-native';
import { eventSelectContent } from '~/constants/functions';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { moment } from '../../services/moment';
import { formatToCurrency } from '../../utils/functions';
import { PointsDetailProps } from './Models';
import {
  getDetailScreenTitle,
  getFormattedHighlightText,
  getFormattedPointsValue,
  getOrigin,
  getPurchaseTypeLabel,
  getTagSubType,
  getTransactionGainType,
  getVehicleInfo,
} from './utils';

const PointsDetailView: FC<PointsDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  handleOpenReportProblem,
  handleCloseReportProblem,
}) => {
  const gainType = getTransactionGainType(transaction);
  const tagSubType = getTagSubType(transaction);
  const screenTitle = getDetailScreenTitle(gainType, transaction.type);
  const vehicleInfo = getVehicleInfo(transaction);
  const purchaseTypeLabel = getPurchaseTypeLabel(tagSubType);
  const origin = getOrigin(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const formattedPointsValue = getFormattedPointsValue(
    transaction.amount,
    transaction.type,
  );
  const cardTitle = transaction.description || '';
  const highlightText = getFormattedHighlightText(
    transaction.date,
    gainType,
    moment,
  );

  const renderDivider = () => {
    return (
      <SeparatorHorizontal
        borderWidth="smaller"
        borderColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
        mt="xxxxs"
      />
    );
  };

  const renderTagContent = () => {
    const hasVehicleInfo = !!vehicleInfo && vehicleInfo !== '';
    const shouldShowOrigin = origin && !hasVehicleInfo;
    const hasPurchaseTypeLabel =
      !!purchaseTypeLabel && purchaseTypeLabel !== '';

    return (
      <>
        {renderDivider()}
        {shouldShowOrigin && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Origem
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {origin}
            </Text>
            {renderDivider()}
          </>
        )}
        {hasVehicleInfo && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tag
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {vehicleInfo}
            </Text>
            {renderDivider()}
          </>
        )}

        {hasPurchaseTypeLabel && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tipo de compra
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {purchaseTypeLabel}
            </Text>
          </>
        )}
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title={screenTitle}
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? 'PLUS_COLOR_02'
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xxxxs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
          />

          <Box mt="xxxs" flex={1} width="100%">
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
              Valor
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {formattedCurrencyValue}
            </Text>

            {gainType === 'TAG' && renderTagContent()}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>
      </BasicScreen>

      <BackDropBottom modalizeRef={modalizeRef as PropsModalizeRef}>
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text
              type="paragraphXXXL"
              color="BRAND_COMPLEMENT_01"
              mb="xs"
              align="center"
            >
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt="xxxxs">
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das
            9h às 17h.
          </Text>
        </Box>

        <Box align="center" width="100%" mt="xxxxs">
          <Text
            type="linkMD"
            color="INTENSE_COLOR_05"
            onPress={handleCloseReportProblem}
            align="center"
          >
            Fechar
          </Text>
        </Box>
      </BackDropBottom>
    </>
  );
};

export default PointsDetailView;

